parameters.jsCode:
const items = $input.all().map(i => i.json);
if (items.length === 0) return [];
const lines = items.map(i => `• *${i.i_title_userside}* — ${i.i_full_schedule || ''} (${i.iid})`).join('\n');
const blocks = [
  { type:'header', text:{ type:'plain_text', text:`📋 오픈알림 미발송 공유회 (${items.length}개)` }},
  { type:'section', text:{ type:'mrkdwn', text: lines }},
  { type:'divider' },
  { type:'section', text:{ type:'mrkdwn', text:'👉 에밀리: Claude Code에서 `/alimtalk 공유회 오픈알림` 실행해주세요' }}
];
return [{ json: { channel:'C0AN2NZ4L7L', text:`오픈알림 미발송 공유회 ${items.length}개`, blocks:JSON.stringify(blocks) }}];

// ⚠️ 임시 테스트 모드 — 테스트 후 제거할 것
const testMode = true;
if (testMode) {
  const t = { num:1, name:'오픈 알림', tid:'KA01TP260224044955111rZoe0O3bxsZ', qt:'all_members', dsql:"iid = 'iid_999'", nm:false, ml:'', utm:'오픈알림' };
  t.program_sql = `SELECT iid, i_title_userside, i_full_schedule, i_alimurl, i_vodurl, i_eventdate, i_submitdate_first, i_submitdate_last, i_paid_tf, i_formid_webflow FROM item WHERE iid = 'iid_999'`;
  return [{ json: t }];
}
const now = new Date();
const kstH = (now.getUTCHours() + 9) % 24;
const kstM = now.getUTCMinutes();
const staticData = $getWorkflowStaticData('global');
let t = null;

if (kstH === 9 && kstM < 3) {
  t = { num:1, name:'오픈 알림', tid:'KA01TP260224044955111rZoe0O3bxsZ', qt:'all_members', dsql:"i_submitdate_first::date = CURRENT_DATE", nm:false, ml:'', utm:'오픈알림' };
} else if (kstH === 10 && kstM < 3) {
  t = { num:2, name:'오픈 리마인드', tid:'KA01TP250718151456335cPBkIZJBkGt', qt:'non_subscribers', dsql:"i_submitdate_first::date + INTERVAL '2 days' = CURRENT_DATE", nm:false, ml:'', utm:'오픈리마인드' };
} else if (kstH === 13 && kstM < 3) {
  t = { num:3, name:'D-1 리마인드', tid:'KA01TP260328003811869hKleQPvW4us', qt:'subscribers', dsql:"i_eventdate = CURRENT_DATE + INTERVAL '1 day'", nm:true, ml:'줌링크를 입력해주세요', utm:null };
} else if (kstH === 13 && kstM >= 3) {
  t = { num:5, name:'할인쿠폰', tid:'KA01TP250729145533585plTadCNvOYu', qt:'non_subscribers', dsql:"i_eventdate = CURRENT_DATE", nm:false, ml:'', utm:'혜택알림' };
} else if (kstH === 14) {
  // ④ 자동: staticData에 줌링크 있으면 모달 없이 발송
  const zoomUrl = staticData.zoomUrl || '';
  if (!zoomUrl) return []; // 줌링크 없으면 스킵
  t = { num:4, name:'당일 리마인드', tid:'KA01TP260328004337699dPIbCrNF2yI', qt:'subscribers', dsql:"i_eventdate = CURRENT_DATE", nm:false, ml:'', utm:null, autoSend:true, link:zoomUrl };
} else if (kstH === 19) {
  t = { num:6, name:'입장 링크', tid:'KA01TP250417061338748mROUNOEEiOF', qt:'subscribers', dsql:"i_eventdate = CURRENT_DATE", nm:true, ml:'라이브혜택을 입력해주세요', utm:null };
} else if (kstH === 20) {
  // ⑦ 자동: staticData에 줌링크+혜택 있으면 모달 없이 발송
  const zoomUrl = staticData.zoomUrl || '';
  const benefits = staticData.benefits || '';
  if (!zoomUrl || !benefits) return [];
  t = { num:7, name:'라이브 시작 알림', tid:'KA01TP260106142352438w6fSAZpbRg4', qt:'subscribers', dsql:"i_eventdate = CURRENT_DATE", nm:false, ml:'', utm:null, autoSend:true, link:zoomUrl, rh:benefits };
} else if (kstH === 22) {
  t = { num:8, name:'혜택 안내', tid:'KA01TP260328003106634WHeu4PCwrp6', qt:'subscribers', dsql:"i_eventdate = CURRENT_DATE", nm:true, ml:'노션 링크를 입력해주세요', utm:null };
} else if (kstH === 18) {
  // ⑨ VOD: D+3
  t = { num:9, name:'VOD 발송', tid:'KA01TP250722045328826Fu3uUAWTGBI', qt:'subscribers', dsql:"i_eventdate + INTERVAL '3 days' = CURRENT_DATE", nm:true, ml:'VOD 링크를 입력해주세요', utm:null };
}
if (!t) return [];
t.program_sql = `SELECT iid, i_title_userside, i_full_schedule, i_alimurl, i_vodurl, i_eventdate, i_submitdate_first, i_submitdate_last, i_paid_tf, i_formid_webflow FROM item WHERE i_type = 'sharing' AND ${t.dsql}`;
return [{ json: t }];

const t = $('Code: 알림톡 판별').first().json;
const item = $json;
const tm = (item.i_full_schedule || '').match(/(\d{1,2}:\d{2})/);
const time = tm ? tm[1] : '20:00';
const days = ['일','월','화','수','목','금','토'];
let ed = '';
if (item.i_submitdate_last) { const d = new Date(item.i_submitdate_last); ed = `${d.getMonth()+1}월${d.getDate()}일(${days[d.getDay()]})`; }
let period = '';
if (item.i_submitdate_first && item.i_submitdate_last) {
  const df = new Date(item.i_submitdate_first);
  const dl = new Date(item.i_submitdate_last);
  period = `${df.getMonth()+1}/${df.getDate()}~${dl.getMonth()+1}/${dl.getDate()}`;
}
const sm = (item.i_alimurl || '').match(/\/sharing\/([^/?]+)/);
const slug = sm ? sm[1] : '';
const kd = new Date(Date.now() + 9*3600000);
const ymd = kd.toISOString().slice(2,10).replace(/-/g,'');
let utmUrl = '';
if (t.utm) utmUrl = `www.selfishclub.xyz/sharing/${slug}?utm_medium=crm&utm_source=alimtalk&utm_campaign=${slug}&utm_content=${ymd}_${t.utm}&utm_term=inbound`;
const iid = (item.iid || '').replace(/[^a-zA-Z0-9_]/g, '');
let csql;
if (t.qt === 'subscribers') {
  csql = `SELECT COUNT(DISTINCT u_phone) as cnt FROM (SELECT p.u_phone FROM purchase p WHERE p.iid='${iid}' AND p.p_cancel_amount=0 AND p.u_name NOT ILIKE '%테스트%' UNION SELECT e.u_phone FROM event e JOIN item i ON e.iid=i.iid WHERE e.iid='${iid}' AND i.i_paid_tf=false AND e.u_name NOT ILIKE '%테스트%') s`;
} else {
  csql = `SELECT COUNT(*) as cnt FROM member m WHERE m.u_membership_tf=true AND m.u_marketing_agree_tf=true AND m.u_phone IS NOT NULL AND m.u_name NOT ILIKE '%테스트%' AND NOT EXISTS (SELECT 1 FROM purchase p WHERE p.u_phone=m.u_phone AND p.iid='${iid}' AND p.p_cancel_amount=0) AND NOT EXISTS (SELECT 1 FROM event e WHERE e.u_phone=m.u_phone AND e.iid='${iid}')`;
}
return [{ json: {
  ...t, iid: item.iid, name: item.i_title_userside, sched: item.i_full_schedule,
  time, ed, period, slug, utmUrl, alimurl: item.i_alimurl || '',
  lh: '✅ 공유회 다시보기 VOD 제공\n✅ 라이브 완주 시 추가 혜택 공개',
  rh: '공유회에서 다룬 내용이 도움이 되셨다면\n짧은 후기를 남겨주세요🙏\n\n✅ 후기 작성 시 다시보기 VOD 무료 제공',
  cpn: '이기적멤버십 프로그램 할인', link: '', count_sql: csql
}}];

const d = $('Code: 변수 준비').first().json;
const cnt = $json.cnt || 0;
if (cnt === 0) return [];

let preview = '';
switch(d.num) {
  case 1:
    preview = `#{이름}님, 알림신청하신\n이기적공유회 모집이 시작됐어요!\n\n🟨 공유회명 : ${d.name}\n🟨 일정 : ${d.sched}\n🟨 신청기간 : ${d.period}`; break;
  case 2:
    preview = `#{이름}님, 알림신청하신
이기적멤버십 프로그램 모집이 시작됐어요!

🟨 프로그램명 : ${d.name}
🟨 일정: ${d.sched}
🟨 신청기간 : ${d.period}`; break;
  case 3:
    preview = `#{이름}님,
신청하신 이기적공유회가
내일 진행됩니다💛

◾공유회명 : ${d.name}
◾일정 : ${d.sched}

라이브 입장링크는
아래 버튼을 확인하세요!`; break;
  case 4:
    preview = `#{이름}님,
신청하신 이기적공유회가
오늘 진행됩니다.

◾공유회명 : ${d.name}
◾일정 : ${d.sched}

늦지 않게 만나요✨`; break;
  case 5:
    preview = `#{이름}님, 가입하신 이기적멤버십
프로그램 할인 쿠폰이 발급되었습니다!

🎁쿠폰명 : ${d.cpn}
⏰사용 종료일 : ${d.ed}

해당 쿠폰은 종료일 이후 자동 소멸되어 적용이 불가합니다.`; break;
  case 6:
    preview = `#{이름}님께서 신청하신
이기적공유회가 ${d.time}에 시작됩니다😆
늦지 않게 입장해주세요!

🟨 공유회명 : ${d.name}
🟨 라이브혜택 :
${d.lh}
👇하단 '라이브 입장하기' 클릭👇`; break;
  case 7:
    preview = `#{이름}님!
신청하신 이기적공유회
${d.name}이 시작됐어요🔥

라이브 참여자에게만 제공되는
특별한 자료집도 받아가세요🎁
✅ ${d.rh}`; break;
  case 8:
    preview = `#{이름}님, 지금 참여하신
공유회 다시보기 및 자세한 안내는
아래 버튼을 눌러 확인해주세요!

◾공유회명 : ${d.name}`; break;
}

const cb = JSON.stringify({
  t:d.num, tid:d.tid, iid:d.iid, name:d.name, sched:d.sched,
  time:d.time, url:d.utmUrl||d.alimurl, slug:d.slug,
  nm:d.nm, ml:d.ml, cnt, lh:d.lh, rh:d.rh, cpn:d.cpn, ed:d.ed, period:d.period||'', qt:d.qt, link:d.link||''
});

const numLabel = {1:'오픈알림',2:'오픈리마인드',3:'D-1 리마인드',4:'당일리마인드',5:'할인쿠폰',6:'입장링크',7:'라이브시작',8:'혜택안내'};
const em = {1:'🔔',2:'📣',3:'📅',4:'🔔',5:'🎁',6:'🔗',7:'🔥',8:'📋'};
const blocks = [
  { type:'header', text:{ type:'plain_text', text:`${em[d.num]||'📢'} [#${d.num} ${numLabel[d.num]||d.name}] 발송 예정` }},
  { type:'section', fields:[
    { type:'mrkdwn', text:`*공유회:*
${d.name}` },
    { type:'mrkdwn', text:`*대상:*
${cnt}명` },
    { type:'mrkdwn', text:`*일정:*
${d.sched}` },
    { type:'mrkdwn', text:`*알림톡:*
#${d.num} ${numLabel[d.num]||d.name}` }
  ]},
  { type:'divider' },
  { type:'section', text:{ type:'mrkdwn', text:`📋 *알림톡 미리보기:*
\`\`\`
${preview}
\`\`\`` }},
  { type:'divider' },
  { type:'actions', elements:[
    { type:'button', text:{ type:'plain_text', text:'✅ 이대로 발송' }, style:'primary', action_id:'cron_approve', value:cb },
    { type:'button', text:{ type:'plain_text', text:'✏️ 수정' }, action_id:'cron_edit', value:cb },
    { type:'button', text:{ type:'plain_text', text:'❌ 취소' }, style:'danger', action_id:'cron_reject', value:cb }
  ]}
];

return [{ json: {
  channel: 'C0AN2NZ4L7L',
  text: `[#${d.num} ${numLabel[d.num]||d.name}] ${d.name} - ${cnt}명`,
  blocks: JSON.stringify(blocks)
}}];

const payloadStr = $input.first().json.body?.payload;
if (!payloadStr) return [{ json: { action: 'unknown' } }];
const payload = JSON.parse(payloadStr);
const staticData = $getWorkflowStaticData('global');

if (payload.type === 'view_submission') {
  const cbid = payload.view?.callback_id;
  const meta = JSON.parse(payload.view?.private_metadata || '{}');
  const vals = payload.view?.state?.values || {};

  if (cbid === 'alimtalk_edit') {
    const updated = { ...meta };
    if (vals.f_name?.v?.value) updated.name = vals.f_name.v.value;
    if (vals.f_sched?.v?.value) updated.sched = vals.f_sched.v.value;
    if (vals.f_time?.v?.value) updated.time = vals.f_time.v.value;
    if (vals.f_lh?.v?.value) updated.lh = vals.f_lh.v.value;
    if (vals.f_rh?.v?.value) updated.rh = vals.f_rh.v.value;
    if (vals.f_cpn?.v?.value) updated.cpn = vals.f_cpn.v.value;
    if (vals.f_ed?.v?.value) updated.ed = vals.f_ed.v.value;
    if (vals.f_period?.v?.value) updated.period = vals.f_period.v.value;
    if (vals.f_link?.v?.value) updated.link = vals.f_link.v.value;

    // ③ D-1: 줌링크 staticData에 저장 → ④⑥⑦ 재사용
    if (updated.t === 3 && updated.link) {
      staticData.zoomUrl = updated.link;
    }
    // ⑥ 입장링크: 라이브혜택 staticData에 저장 → ⑦ 재사용
    if (updated.t === 6 && updated.lh) {
      staticData.benefits = updated.lh;
    }

    return [{ json: { action: 'edit_submit', ...updated, user_name: payload.user?.name || '' } }];
  }

  if (cbid === 'alimtalk_url') {
    const url = vals.url_block?.url_input?.value || '';
    const result = { action: 'modal_submit', input_url: url, ...meta, user_name: payload.user?.name || '' };

    // ③ URL 모달에서도 줌링크 저장
    if (meta.t === 3 && url) {
      staticData.zoomUrl = url;
    }
    if (meta.t === 6 && url) {
      // ⑥은 URL이 아니라 라이브혜택이지만, URL 모달이면 줌링크
    }

    return [{ json: result }];
  }

  return [{ json: { action: 'unknown' } }];
}

const act = payload.actions?.[0];
const cb = JSON.parse(act?.value || '{}');
const base = { ch: payload.channel?.id, ts: payload.message?.ts, user_name: payload.user?.name || '', ...cb };

if (act?.action_id === 'cron_reject') return [{ json: { action: 'reject', ...base } }];
if (act?.action_id === 'cron_edit') return [{ json: { action: 'edit', trigger_id: payload.trigger_id, ...base } }];
if (act?.action_id === 'cron_approve') {
  // ④⑦ 자동발송: 줌링크가 staticData에 있으면 바로 승인
  if (cb.t === 4 || cb.t === 7) {
    const link = staticData.zoomUrl || cb.link || '';
    if (link) {
      return [{ json: { action: 'approve_direct', input_url: link, ...base, link } }];
    }
  }

  if (cb.nm && !cb.link) return [{ json: { action: 'approve_modal', trigger_id: payload.trigger_id, ...base } }];
  return [{ json: { action: 'approve_direct', input_url: cb.link || null, ...base } }];
}
return [{ json: { action: 'unknown' } }];

parameters.jsonBody:
={{ JSON.stringify({ trigger_id: $json.trigger_id, view: {
  type: 'modal', callback_id: 'alimtalk_url', title: { type: 'plain_text', text: '링크 입력' },
  submit: { type: 'plain_text', text: '발송' }, close: { type: 'plain_text', text: '취소' },
  private_metadata: JSON.stringify({ t:$json.t, tid:$json.tid, iid:$json.iid, name:$json.name, sched:$json.sched, time:$json.time, slug:$json.slug, nm:$json.nm, ml:$json.ml, cnt:$json.cnt, lh:$json.lh, rh:$json.rh, cpn:$json.cpn, ed:$json.ed, period:$json.period||'', qt:$json.qt, link:'', ch:$json.ch, ts:$json.ts }),
  blocks: [{ type:'input', block_id:'url_block', element:{ type:'url_text_input', action_id:'url_input', placeholder:{ type:'plain_text', text: $json.ml } }, label:{ type:'plain_text', text: $json.ml } }]
}}) }}

parameters.jsCode:
const d = $json;
const meta = JSON.stringify({ t:d.t, tid:d.tid, iid:d.iid, name:d.name, sched:d.sched, time:d.time, url:d.url||'', slug:d.slug, nm:d.nm, ml:d.ml, cnt:d.cnt, lh:d.lh, rh:d.rh, cpn:d.cpn, ed:d.ed, period:d.period||'', qt:d.qt, link:d.link||'', ch:d.ch, ts:d.ts });

const blocks = [];
// ① 오픈알림 — 공유회명에 카피 (multiline)
if (d.t === 1) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.name||'' }, label:{ type:'plain_text', text:'공유회명 (카피 입력)' }});
  blocks.push({ type:'input', block_id:'f_sched', element:{ type:'plain_text_input', action_id:'v', initial_value: d.sched||'' }, label:{ type:'plain_text', text:'일정' }});
  blocks.push({ type:'input', block_id:'f_period', element:{ type:'plain_text_input', action_id:'v', initial_value: d.period||'' }, label:{ type:'plain_text', text:'신청기간' }});
}
// ② 오픈리마인드 — 프로그램명에 카피 (multiline)
if (d.t === 2) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.name||'' }, label:{ type:'plain_text', text:'프로그램명 (카피 입력)' }});
  blocks.push({ type:'input', block_id:'f_sched', element:{ type:'plain_text_input', action_id:'v', initial_value: d.sched||'' }, label:{ type:'plain_text', text:'일정' }});
  blocks.push({ type:'input', block_id:'f_period', element:{ type:'plain_text_input', action_id:'v', initial_value: d.period||'' }, label:{ type:'plain_text', text:'신청기간 (예: 3/18~3/31)' }});
}
// ③ D-1 리마인드 — 공유회명+일정
if (d.t === 3) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', initial_value: d.name||'' }, label:{ type:'plain_text', text:'공유회명' }});
  blocks.push({ type:'input', block_id:'f_sched', element:{ type:'plain_text_input', action_id:'v', initial_value: d.sched||'' }, label:{ type:'plain_text', text:'일정' }});
  blocks.push({ type:'input', block_id:'f_link', optional:true, element:{ type:'plain_text_input', action_id:'v', initial_value: d.link||'', placeholder:{ type:'plain_text', text:'줌링크를 입력해주세요' }}, label:{ type:'plain_text', text:'줌링크 (옵션)' }});
}
// ④ 당일 리마인드 — 공유회명+일정
if (d.t === 4) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', initial_value: d.name||'' }, label:{ type:'plain_text', text:'공유회명' }});
  blocks.push({ type:'input', block_id:'f_sched', element:{ type:'plain_text_input', action_id:'v', initial_value: d.sched||'' }, label:{ type:'plain_text', text:'일정' }});
  blocks.push({ type:'input', block_id:'f_link', optional:true, element:{ type:'plain_text_input', action_id:'v', initial_value: d.link||'', placeholder:{ type:'plain_text', text:'줌링크를 입력해주세요' }}, label:{ type:'plain_text', text:'줌링크 (옵션)' }});
}
// ⑤ 할인쿠폰 — 쿠폰명(multiline)+종료일
if (d.t === 5) {
  blocks.push({ type:'input', block_id:'f_cpn', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.cpn||'' }, label:{ type:'plain_text', text:'쿠폰명 (카피 입력)' }});
  blocks.push({ type:'input', block_id:'f_ed', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.ed||'' }, label:{ type:'plain_text', text:'종료일 + 안내문구' }});
}
