라이브 참여자에게만 제공되는
특별한 자료집도 받아가세요🎁
✅ ${d.rh}`; break;
  case 8:
    preview = `#{이름}님, 지금 참여하신
공유회 다시보기 및 자세한 안내는
아래 버튼을 눌러 확인해주세요!

◾공유회명 : ${d.name}`; break;
}

const cb = JSON.stringify({
  t:d.num, tid:d.tid, iid:d.iid, name:d.name, sched:d.sched,
  time:d.time, url:d.utmUrl||d.alimurl, slug:d.slug,
  nm:d.nm, ml:d.ml, cnt, lh:d.lh, rh:d.rh, cpn:d.cpn, ed:d.ed, period:d.period||'', qt:d.qt, link:d.link||''
});

const numLabel = {1:'오픈알림',2:'오픈리마인드',3:'D-1 리마인드',4:'당일리마인드',5:'할인쿠폰',6:'입장링크',7:'라이브시작',8:'혜택안내'};
const em = {1:'🔔',2:'📣',3:'📅',4:'🔔',5:'🎁',6:'🔗',7:'🔥',8:'📋'};
const blocks = [
  { type:'header', text:{ type:'plain_text', text:`${em[d.num]||'📢'} [#${d.num} ${numLabel[d.num]||d.name}] 발송 예정` }},
  { type:'section', fields:[
    { type:'mrkdwn', text:`*공유회:*
${d.name}` },
    { type:'mrkdwn', text:`*대상:*
${cnt}명` },
    { type:'mrkdwn', text:`*일정:*
${d.sched}` },
    { type:'mrkdwn', text:`*알림톡:*
#${d.num} ${numLabel[d.num]||d.name}` }
  ]},
  { type:'divider' },
  { type:'section', text:{ type:'mrkdwn', text:`📋 *알림톡 미리보기:*
\`\`\`
${preview}
\`\`\`` }},
  { type:'divider' },
  { type:'actions', elements:[
    { type:'button', text:{ type:'plain_text', text:'✅ 이대로 발송' }, style:'primary', action_id:'cron_approve', value:cb },
    { type:'button', text:{ type:'plain_text', text:'✏️ 수정' }, action_id:'cron_edit', value:cb },
    { type:'button', text:{ type:'plain_text', text:'❌ 취소' }, style:'danger', action_id:'cron_reject', value:cb }
  ]}
];

return [{ json: {
  channel: 'C0AN2NZ4L7L',
  text: `[#${d.num} ${numLabel[d.num]||d.name}] ${d.name} - ${cnt}명`,
  blocks: JSON.stringify(blocks)
}}];

const payloadStr = $input.first().json.body?.payload;
if (!payloadStr) return [{ json: { action: 'unknown' } }];
const payload = JSON.parse(payloadStr);
const staticData = $getWorkflowStaticData('global');

if (payload.type === 'view_submission') {
  const cbid = payload.view?.callback_id;
  const meta = JSON.parse(payload.view?.private_metadata || '{}');
  const vals = payload.view?.state?.values || {};

  if (cbid === 'alimtalk_edit') {
    const updated = { ...meta };
    if (vals.f_name?.v?.value) updated.name = vals.f_name.v.value;
    if (vals.f_sched?.v?.value) updated.sched = vals.f_sched.v.value;
    if (vals.f_time?.v?.value) updated.time = vals.f_time.v.value;
    if (vals.f_lh?.v?.value) updated.lh = vals.f_lh.v.value;
    if (vals.f_rh?.v?.value) updated.rh = vals.f_rh.v.value;
    if (vals.f_cpn?.v?.value) updated.cpn = vals.f_cpn.v.value;
    if (vals.f_ed?.v?.value) updated.ed = vals.f_ed.v.value;
    if (vals.f_period?.v?.value) updated.period = vals.f_period.v.value;
    if (vals.f_link?.v?.value) updated.link = vals.f_link.v.value;

    // ③ D-1: 줌링크 staticData에 저장 → ④⑥⑦ 재사용
    if (updated.t === 3 && updated.link) {
      staticData.zoomUrl = updated.link;
    }
    // ⑥ 입장링크: 라이브혜택 staticData에 저장 → ⑦ 재사용
    if (updated.t === 6 && updated.lh) {
      staticData.benefits = updated.lh;
    }

    return [{ json: { action: 'edit_submit', ...updated, user_name: payload.user?.name || '' } }];
  }

  if (cbid === 'alimtalk_url') {
    const url = vals.url_block?.url_input?.value || '';
    const result = { action: 'modal_submit', input_url: url, ...meta, user_name: payload.user?.name || '' };

    // ③ URL 모달에서도 줌링크 저장
    if (meta.t === 3 && url) {
      staticData.zoomUrl = url;
    }
    if (meta.t === 6 && url) {
      // ⑥은 URL이 아니라 라이브혜택이지만, URL 모달이면 줌링크
    }

    return [{ json: result }];
  }

  return [{ json: { action: 'unknown' } }];
}

const act = payload.actions?.[0];
const cb = JSON.parse(act?.value || '{}');
const base = { ch: payload.channel?.id, ts: payload.message?.ts, user_name: payload.user?.name || '', ...cb };

if (act?.action_id === 'cron_reject') return [{ json: { action: 'reject', ...base } }];
if (act?.action_id === 'cron_edit') return [{ json: { action: 'edit', trigger_id: payload.trigger_id, ...base } }];
if (act?.action_id === 'cron_approve') {
  // ④⑦ 자동발송: 줌링크가 staticData에 있으면 바로 승인
  if (cb.t === 4 || cb.t === 7) {
    const link = staticData.zoomUrl || cb.link || '';
    if (link) {
      return [{ json: { action: 'approve_direct', input_url: link, ...base, link } }];
    }
  }

  if (cb.nm && !cb.link) return [{ json: { action: 'approve_modal', trigger_id: payload.trigger_id, ...base } }];
  return [{ json: { action: 'approve_direct', input_url: cb.link || null, ...base } }];
}
return [{ json: { action: 'unknown' } }];

