parameters.jsCode:
const d = $json;
const meta = JSON.stringify({ t:d.t, tid:d.tid, iid:d.iid, name:d.name, sched:d.sched, time:d.time, url:d.url||'', slug:d.slug, nm:d.nm, ml:d.ml, cnt:d.cnt, lh:d.lh, rh:d.rh, cpn:d.cpn, ed:d.ed, period:d.period||'', qt:d.qt, link:d.link||'', ch:d.ch, ts:d.ts });

const blocks = [];
// ① 오픈알림 — 공유회명에 카피 (multiline)
if (d.t === 1) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.name||'' }, label:{ type:'plain_text', text:'공유회명 (카피 입력)' }});
  blocks.push({ type:'input', block_id:'f_sched', element:{ type:'plain_text_input', action_id:'v', initial_value: d.sched||'' }, label:{ type:'plain_text', text:'일정' }});
  blocks.push({ type:'input', block_id:'f_period', element:{ type:'plain_text_input', action_id:'v', initial_value: d.period||'' }, label:{ type:'plain_text', text:'신청기간' }});
}
// ② 오픈리마인드 — 프로그램명에 카피 (multiline)
if (d.t === 2) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.name||'' }, label:{ type:'plain_text', text:'프로그램명 (카피 입력)' }});
  blocks.push({ type:'input', block_id:'f_sched', element:{ type:'plain_text_input', action_id:'v', initial_value: d.sched||'' }, label:{ type:'plain_text', text:'일정' }});
  blocks.push({ type:'input', block_id:'f_period', element:{ type:'plain_text_input', action_id:'v', initial_value: d.period||'' }, label:{ type:'plain_text', text:'신청기간 (예: 3/18~3/31)' }});
}
// ③ D-1 리마인드 — 공유회명+일정
if (d.t === 3) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', initial_value: d.name||'' }, label:{ type:'plain_text', text:'공유회명' }});
  blocks.push({ type:'input', block_id:'f_sched', element:{ type:'plain_text_input', action_id:'v', initial_value: d.sched||'' }, label:{ type:'plain_text', text:'일정' }});
  blocks.push({ type:'input', block_id:'f_link', optional:true, element:{ type:'plain_text_input', action_id:'v', initial_value: d.link||'', placeholder:{ type:'plain_text', text:'줌링크를 입력해주세요' }}, label:{ type:'plain_text', text:'줌링크 (옵션)' }});
}
// ④ 당일 리마인드 — 공유회명+일정
if (d.t === 4) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', initial_value: d.name||'' }, label:{ type:'plain_text', text:'공유회명' }});
  blocks.push({ type:'input', block_id:'f_sched', element:{ type:'plain_text_input', action_id:'v', initial_value: d.sched||'' }, label:{ type:'plain_text', text:'일정' }});
  blocks.push({ type:'input', block_id:'f_link', optional:true, element:{ type:'plain_text_input', action_id:'v', initial_value: d.link||'', placeholder:{ type:'plain_text', text:'줌링크를 입력해주세요' }}, label:{ type:'plain_text', text:'줌링크 (옵션)' }});
}
// ⑤ 할인쿠폰 — 쿠폰명(multiline)+종료일
if (d.t === 5) {
  blocks.push({ type:'input', block_id:'f_cpn', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.cpn||'' }, label:{ type:'plain_text', text:'쿠폰명 (카피 입력)' }});
  blocks.push({ type:'input', block_id:'f_ed', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.ed||'' }, label:{ type:'plain_text', text:'종료일 + 안내문구' }});
}
// ⑥ 입장링크 — 공유회명+시간+라이브혜택+줌링크
if (d.t === 6) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', initial_value: d.name||'' }, label:{ type:'plain_text', text:'공유회명' }});
  blocks.push({ type:'input', block_id:'f_time', element:{ type:'plain_text_input', action_id:'v', initial_value: d.time||'20:00' }, label:{ type:'plain_text', text:'시간' }});
  blocks.push({ type:'input', block_id:'f_lh', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.lh||'' }, label:{ type:'plain_text', text:'라이브혜택' }});
  blocks.push({ type:'input', block_id:'f_link', optional:true, element:{ type:'plain_text_input', action_id:'v', initial_value: d.link||'', placeholder:{ type:'plain_text', text:'줌링크를 입력해주세요' }}, label:{ type:'plain_text', text:'줌링크' }});
}
// ⑦ 라이브 시작알림 — 프로그램명+자료집리스트+줌링크
if (d.t === 7) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', initial_value: d.name||'' }, label:{ type:'plain_text', text:'프로그램명' }});
  blocks.push({ type:'input', block_id:'f_rh', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.rh||'' }, label:{ type:'plain_text', text:'자료집리스트' }});
  blocks.push({ type:'input', block_id:'f_link', optional:true, element:{ type:'plain_text_input', action_id:'v', initial_value: d.link||'', placeholder:{ type:'plain_text', text:'줌링크를 입력해주세요' }}, label:{ type:'plain_text', text:'줌링크' }});
}
// ⑧ 혜택안내(노션) — 공유회명(multiline)+노션링크
if (d.t === 8) {
  blocks.push({ type:'input', block_id:'f_name', element:{ type:'plain_text_input', action_id:'v', multiline:true, initial_value: d.name||'' }, label:{ type:'plain_text', text:'공유회명 (카피 입력)' }});
  blocks.push({ type:'input', block_id:'f_link', optional:true, element:{ type:'plain_text_input', action_id:'v', initial_value: d.link||'', placeholder:{ type:'plain_text', text:'노션 링크를 입력해주세요' }}, label:{ type:'plain_text', text:'노션 링크' }});
}

return [{ json: { trigger_id: d.trigger_id, meta, blocks: JSON.stringify(blocks) }}];

const d = $json;
let preview = '';
switch(d.t) {
  case 2:
    preview = `\{이름\}님, 알림신청하신
이기적공유회 모집이 시작됐어요!

🟨 공유회명 : ${d.name}
🟨 일정 : ${d.sched}
🟨 신청기간 : ${d.period}`; break;
  case 3:
    preview = `\{이름\}님께서 신청하신
이기적공유회가 내일 진행됩니다💛

입장링크는 ${d.time}에
카카오톡으로 발송됩니다.

🟨 공유회명 : ${d.name}
🟨 일정 : ${d.sched}
🟨 라이브혜택 :
${d.lh}`; break;
  case 4:
    preview = `\{이름\}님께서 신청하신
이기적공유회가 오늘 시작됩니다💛

입장링크는 ${d.time}에
카카오톡으로 발송됩니다.

🟨 공유회명 : ${d.name}
🟨 일정 : ${d.sched}
🟨 라이브혜택 :
${d.lh}`; break;
  case 5:
    preview = `\{이름\}님, 가입하신 이기적멤버십
프로그램 할인 쿠폰이 발급되었습니다!

🎁쿠폰명 : ${d.cpn}
⏰사용 종료일 : ${d.ed}

해당 쿠폰은 종료일 이후 자동 소멸되어 적용이 불가합니다.`; break;
  case 6:
    preview = `\{이름\}님께서 신청하신
이기적공유회가 ${d.time}에 시작됩니다😆
늦지 않게 입장해주세요!

🟨 공유회명 : ${d.name}
🟨 라이브혜택 :
${d.lh}
👇하단 '라이브 입장하기' 클릭👇`; break;
  case 7:
    preview = `\{이름\}님
신청하신 이기적공유회
후기를 남겨주세요📝

${d.rh}

아래 링크를 클릭하시면
후기 설문으로 넘어갑니다.`; break;
}
const linkNote = d.link ? `
✅ 링크: ${d.link}` : (d.nm ? '
⚠️ 링크 미입력 (수정에서 입력 가능)' : '');
const cb = JSON.stringify({
  t:d.t, tid:d.tid, iid:d.iid, name:d.name, sched:d.sched, time:d.time,
  url:d.url||'', slug:d.slug, nm:d.nm, ml:d.ml, cnt:d.cnt,
  lh:d.lh, rh:d.rh, cpn:d.cpn, ed:d.ed, period:d.period||'', qt:d.qt, link:d.link||''
});
const em = {2:'📣',3:'📅',4:'🔔',5:'🎁',6:'🔗',7:'📝'};
const blocks = [
  { type:'header', text:{ type:'plain_text', text:`${em[d.t]||'📢'} [#${d.t} ${d.name}] 수정됨 ✏️` }},
  { type:'section', text:{ type:'mrkdwn', text:`*대상:* ${d.cnt}명${linkNote}` }},
  { type:'divider' },
  { type:'section', text:{ type:'mrkdwn', text:`📋 *수정된 미리보기:*
\`\`\`
${preview}
\`\`\`` }},
  { type:'divider' },
  { type:'actions', elements:[
    { type:'button', text:{ type:'plain_text', text:'✅ 이대로 발송' }, style:'primary', action_id:'cron_approve', value:cb },
    { type:'button', text:{ type:'plain_text', text:'✏️ 수정' }, action_id:'cron_edit', value:cb },
    { type:'button', text:{ type:'plain_text', text:'❌ 취소' }, style:'danger', action_id:'cron_reject', value:cb }
  ]}
];
return [{ json: { channel: d.ch, text: `[수정됨] #${d.t} ${d.name}`, blocks: JSON.stringify(blocks) }}];

const d = $('Code: 파싱').first().json;
const iid = (d.iid || '').replace(/[^a-zA-Z0-9_]/g, '');
let sql;
if (d.qt === 'subscribers') {
  sql = `SELECT DISTINCT sub.u_name, sub.u_phone FROM (SELECT p.u_name, p.u_phone FROM purchase p WHERE p.iid='${iid}' AND p.p_cancel_amount=0 AND p.u_name NOT ILIKE '%테스트%' UNION SELECT e.u_name, e.u_phone FROM event e JOIN item i ON e.iid=i.iid WHERE e.iid='${iid}' AND i.i_paid_tf=false AND e.u_name NOT ILIKE '%테스트%') sub`;
} else {
  sql = `SELECT m.u_name, m.u_phone FROM member m WHERE m.u_membership_tf=true AND m.u_marketing_agree_tf=true AND m.u_phone IS NOT NULL AND m.u_name NOT ILIKE '%테스트%' AND NOT EXISTS (SELECT 1 FROM purchase p WHERE p.u_phone=m.u_phone AND p.iid='${iid}' AND p.p_cancel_amount=0) AND NOT EXISTS (SELECT 1 FROM event e WHERE e.u_phone=m.u_phone AND e.iid='${iid}')`;
}
return [{ json: { recipients_sql: sql } }];

// ⚠️ iid_999 테스트 안전장치 — 에밀리 1명만 발송
const d_check = $('Code: 파싱').first().json;
if (d_check.iid === 'iid_999') {
  return [{ json: { u_phone: '01082948909', u_name: '에밀리', t: d_check.t, tid: d_check.tid,
    v_이름: '에밀리', v_공유회명: d_check.name || '', v_프로그램명: d_check.name || '',
    v_일정: d_check.sched || '', v_기간: d_check.period || '', v_시간: d_check.time || '20:00',
    v_라이브혜택: d_check.lh || '', v_자료집리스트: d_check.rh || '',
    v_쿠폰명: d_check.cpn || '', v_종료일: d_check.ed || '',
    v_url: d_check.link || d_check.url || '', v_날짜: '', v_채널: '셀피쉬클럽' }}];
}
const d = $('Code: 파싱').first().json;
const recipients = $input.all().map(i => i.json);
return recipients.map(r => {
  const base = { u_phone: r.u_phone, u_name: r.u_name, t: d.t, tid: d.tid };
  switch(d.t) {
    case 2:
      return { json: { ...base, v_이름:r.u_name, v_공유회명:d.name, v_일정:d.sched, v_기간:d.period||'', v_url:d.url||'' }};
    case 3: case 4:
      return { json: { ...base, v_이름:r.u_name, v_시간:d.time, v_공유회명:d.name, v_일정:d.sched, v_라이브혜택:d.lh }};
    case 5:
      return { json: { ...base, v_이름:r.u_name, v_쿠폰명:d.cpn, v_종료일:d.ed, v_url:d.url||'' }};
    case 6:
      return { json: { ...base, v_이름:r.u_name, v_시간:d.time, v_공유회명:d.name, v_라이브혜택:d.lh, v_url:d.input_url||d.link||'' }};
    case 7:
      return { json: { ...base, v_이름:r.u_name, v_후기혜택:d.rh, v_url:d.input_url||d.link||'' }};
    default: return { json: base };
  }
});

parameters.jsonBody:
={
